					message: result.details?.error?.message || textContent,
				},
			};
		}

		// Success but couldn't parse structured data - return what we have
		return {
			success: true,
			issue: {
				id: "",
				identifier: textContent.split("\n")[0] || "Unknown",
				url: undefined,
			},
		};
	} catch (error) {
		const message = error instanceof Error ? error.message : String(error);
		return {
			success: false,
			error: { message },
		};
	}
}
